namespace sv_f3d1798844674b2f969d9c96232173f5.Models;

public class WizardData
{
    // Step 1 — Personal Info
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";

    // Step 2 — Experience
    public List<JobExperience> Experience { get; set; } = new();

    // Step 3 — References
    public List<Reference> References { get; set; } = new();

    // Progress tracking
    public HashSet<int> CompletedSteps { get; set; } = new();
    public int CurrentStep { get; set; } = 1;
}

public class JobExperience
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Duration { get; set; } = "";
}

public class Reference
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Phone { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_f3d1798844674b2f969d9c96232173f5.Models;

namespace sv_f3d1798844674b2f969d9c96232173f5.Services;

/// <summary>
/// Singleton service that stores wizard state keyed by session cookie.
/// Both the static SSR layout and interactive circuit pages share this
/// instance, giving them a common view of each applicant's progress.
/// </summary>
public class WizardStateService
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new WizardData());

    public WizardData? TryGet(string sessionId)
        => _store.TryGetValue(sessionId, out var data) ? data : null;

    public void Remove(string sessionId)
        => _store.TryRemove(sessionId, out _);
}

namespace sv_f3d1798844674b2f969d9c96232173f5.Middleware;

/// <summary>
/// Ensures every request has a WizardSessionId cookie and stashes the
/// value in HttpContext.Items so both the static layout and interactive
/// pages can read it without parsing cookies themselves.
/// </summary>
public class WizardSessionMiddleware
{
    private readonly RequestDelegate _next;
    public const string CookieName = "WizardSessionId";
    public const string ItemsKey = "WizardSessionId";

    public WizardSessionMiddleware(RequestDelegate next) => _next = next;

    public async Task InvokeAsync(HttpContext context)
    {
        if (!context.Request.Cookies.TryGetValue(CookieName, out var sessionId))
        {
            sessionId = Guid.NewGuid().ToString();
            context.Response.Cookies.Append(CookieName, sessionId, new CookieOptions
            {
                HttpOnly = true,
                SameSite = SameSiteMode.Strict,
                Secure = context.Request.IsHttps,
                MaxAge = TimeSpan.FromHours(2)
            });
        }

        // Make it available to SSR components via HttpContext.Items
        context.Items[ItemsKey] = sessionId;
        await _next(context);
    }
}

using Microsoft.AspNetCore.Components;
using sv_f3d1798844674b2f969d9c96232173f5.Models;
using sv_f3d1798844674b2f969d9c96232173f5.Services;

namespace sv_f3d1798844674b2f969d9c96232173f5.Components.Pages.Apply;

/// <summary>
/// Base class for each wizard step page.
///
/// During prerender (SSR), HttpContext is available so we read the session
/// cookie from HttpContext.Items and persist it via PersistentComponentState.
/// When the interactive circuit starts, HttpContext is null, so we restore
/// the session ID from PersistentComponentState. Either way we end up with
/// the same session key into the singleton WizardStateService.
/// </summary>
public abstract class WizardPageBase : ComponentBase, IDisposable
{
    [Inject] protected WizardStateService StateService { get; set; } = default!;
    [Inject] protected PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] protected NavigationManager Navigation { get; set; } = default!;
    [CascadingParameter] private HttpContext? HttpContext { get; set; }

    protected WizardData WizardData { get; private set; } = new();
    protected abstract int StepNumber { get; }

    private string _sessionId = "";
    private PersistingComponentStateSubscription _subscription;

    private static readonly string[] StepUrls =
    [
        "/apply/personal-info",
        "/apply/experience",
        "/apply/references",
        "/apply/review"
    ];

    protected override void OnInitialized()
    {
        _subscription = PersistentState.RegisterOnPersisting(PersistState);

        if (HttpContext is not null)
        {
            // Prerender phase — HttpContext available
            _sessionId = HttpContext.Items["WizardSessionId"]?.ToString() ?? "";
        }
        else if (PersistentState.TryTakeFromJson<string>("WizardSessionId", out var restored))
        {
            // Circuit phase — restore from persisted state
            _sessionId = restored ?? "";
        }

        if (!string.IsNullOrEmpty(_sessionId))
        {
            WizardData = StateService.GetOrCreate(_sessionId);
            WizardData.CurrentStep = StepNumber;
        }
    }

    private Task PersistState()
    {
        PersistentState.PersistAsJson("WizardSessionId", _sessionId);
        return Task.CompletedTask;
    }

    protected void CompleteStepAndNavigate()
    {
        WizardData.CompletedSteps.Add(StepNumber);
        var nextIndex = Math.Min(StepNumber, StepUrls.Length - 1); // StepNumber is 1-based
        Navigation.NavigateTo(StepUrls[nextIndex]);
    }

    protected void NavigateBack()
    {
        var prevIndex = Math.Max(StepNumber - 2, 0);
        Navigation.NavigateTo(StepUrls[prevIndex]);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

