/// Both the static SSR layout and interactive circuit pages share this
/// instance, giving them a common view of each applicant's progress.
/// </summary>
public class WizardStateService
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId)
        => _store.GetOrAdd(sessionId, _ => new WizardData());

    public WizardData? TryGet(string sessionId)
        => _store.TryGetValue(sessionId, out var data) ? data : null;

    public void Remove(string sessionId)
        => _store.TryRemove(sessionId, out _);
}

