@* 
    Static SSR component — no render mode.
    Reads wizard state from the singleton service using the session cookie.
    This works because the layout is re-rendered on every navigation request.
*@

@using sv_f3d1798844674b2f969d9c96232173f5.Services
@using sv_f3d1798844674b2f969d9c96232173f5.Middleware
@inject WizardStateService StateService

@{
    var sessionId = HttpContext?.Items[WizardSessionMiddleware.ItemsKey]?.ToString();
    var wizardData = !string.IsNullOrEmpty(sessionId) ? StateService.TryGet(sessionId) : null;
    var isWizardRoute = HttpContext?.Request.Path.StartsWithSegments("/apply") == true;
}

@if (isWizardRoute && wizardData is not null)
{
    <div class="wizard-progress d-flex align-items-center gap-2 py-2">
        @for (int i = 1; i <= 4; i++)
        {
            var step = i;
            var label = step switch
            {
                1 => "Personal Info",
                2 => "Experience",
                3 => "References",
                4 => "Review",
                _ => ""
            };
            var isCompleted = wizardData.CompletedSteps.Contains(step);
            var isCurrent = wizardData.CurrentStep == step;

            <div class="d-flex align-items-center">
                <span class="badge rounded-pill @(isCompleted ? "bg-success" : isCurrent ? "bg-primary" : "bg-secondary")">
                    @(isCompleted ? "✓" : step.ToString())
                </span>
                <span class="ms-1 small @(isCurrent ? "fw-bold" : "")">@label</span>
            </div>

            if (step < 4)
            {
                <hr class="flex-grow-1 mx-1" style="border-top: 2px @(isCompleted ? "solid green" : "dashed #ccc");" />
            }
        }
    </div>
    <div class="small text-muted mb-2">Step @wizardData.CurrentStep of 4</div>
}

@page "/apply/personal-info"
@rendermode InteractiveServer
@inherits WizardPageBase
@using sv_f3d1798844674b2f969d9c96232173f5.Components.Pages.Apply

<PageTitle>Apply — Personal Info</PageTitle>

<h3>Step 1: Personal Information</h3>

<EditForm Model="WizardData" OnValidSubmit="CompleteStepAndNavigate" FormName="personalInfo">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="WizardData.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="WizardData.Email" />
    </div>

    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    protected override int StepNumber => 1;
}

