            <input class="form-control" @bind="exp.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Duration</label>
            <input class="form-control" @bind="exp.Duration" />
        </div>
        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveExperience(index)">Remove</button>
